+        let events = sink.events();
+        let mut kinds: Vec<_> = events.iter().map(|(_, mk)| mk.stream_kind).collect();
+        kinds.sort();
+
+        // Lifecycle (rank 0) should sort before Egress (rank 3)
+        assert_eq!(kinds[0], StreamKind::Lifecycle);
